/**
 * MAZE RUNNER — All-in-One Server + Game
 * Deploy on Railway.app for free, share the link!
 *
 * Local:   node index.js  →  open http://localhost:3000
 * Railway: auto-runs, gives you a public URL
 */

const http   = require("http");
const crypto = require("crypto");

const PORT = process.env.PORT || 3000;

// ── Embedded game HTML (base64) ───────────────────────────────────────────────
const GAME_HTML_B64 = "";
const GAME_HTML = Buffer.from(GAME_HTML_B64, "base64");

// ── WebSocket helpers ─────────────────────────────────────────────────────────
function wsHandshake(req, socket) {
  const key = req.headers["sec-websocket-key"];
  const accept = crypto.createHash("sha1")
    .update(key + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11").digest("base64");
  socket.write(
    "HTTP/1.1 101 Switching Protocols\r\n" +
    "Upgrade: websocket\r\nConnection: Upgrade\r\n" +
    `Sec-WebSocket-Accept: ${accept}\r\n\r\n`
  );
}

function wsSend(socket, msg) {
  if (socket.destroyed) return;
  const data = Buffer.from(typeof msg === "string" ? msg : JSON.stringify(msg));
  const len = data.length;
  let hdr;
  if (len < 126)      { hdr = Buffer.from([0x81, len]); }
  else if (len < 65536){ hdr = Buffer.alloc(4); hdr[0]=0x81; hdr[1]=126; hdr.writeUInt16BE(len,2); }
  else                 { hdr = Buffer.alloc(10); hdr[0]=0x81; hdr[1]=127; hdr.writeBigUInt64BE(BigInt(len),2); }
  try { socket.write(Buffer.concat([hdr, data])); } catch(e) {}
}

function wsParseFrames(buf) {
  const out = []; let off = 0;
  while (off + 2 <= buf.length) {
    const op = buf[off] & 0x0f, masked = (buf[off+1] & 0x80) !== 0;
    let plen = buf[off+1] & 0x7f, hlen = 2;
    if (plen === 126) { if (off+4 > buf.length) break; plen = buf.readUInt16BE(off+2); hlen = 4; }
    else if (plen === 127) { if (off+10 > buf.length) break; plen = Number(buf.readBigUInt64BE(off+2)); hlen = 10; }
    const moff = off+hlen, doff = moff+(masked?4:0);
    if (doff+plen > buf.length) break;
    const pl = Buffer.alloc(plen);
    if (masked) { const m = buf.slice(moff,moff+4); for(let i=0;i<plen;i++) pl[i]=buf[doff+i]^m[i%4]; }
    else buf.copy(pl, 0, doff, doff+plen);
    if (op === 0x8) out.push({type:"close"});
    else if (op === 1 || op === 2) { try { out.push({type:"msg", data:pl.toString()}); } catch(e){} }
    off = doff+plen;
  }
  return out;
}

// ── Game state ────────────────────────────────────────────────────────────────
const lobbies = {}, clients = {};
let nextId = 1;

function genCode() {
  const ch = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  return Array.from({length:6},()=>ch[Math.floor(Math.random()*ch.length)]).join("");
}

function broadcast(code, msg, excludeId) {
  const l = lobbies[code]; if (!l) return;
  for (const pid of l.players) {
    if (pid === excludeId) continue;
    const cl = clients[pid]; if (cl) wsSend(cl.socket, msg);
  }
}

function lobbyInfo(code) {
  const l = lobbies[code]; if (!l) return null;
  return {
    code, host: l.host, started: l.started,
    mazeSeed: l.mazeSeed, day: l.day, isDay: l.isDay,
    players: l.players.map(pid=>clients[pid]).filter(Boolean).map(cl=>({
      id:cl.id, name:cl.playerName, appearance:cl.appearance,
      x:cl.x, y:cl.y, hp:cl.hp, equipped:cl.equipped, inMaze:cl.inMaze
    }))
  };
}

function handle(id, raw) {
  let msg; try { msg = JSON.parse(raw); } catch(e){ return; }
  const cl = clients[id]; if (!cl) return;
  switch(msg.type) {
    case "CREATE_LOBBY": {
      const code = genCode();
      lobbies[code] = { host:id, players:[id], started:false,
        mazeSeed:Math.floor(Math.random()*50)+1, day:1, isDay:true, time:0 };
      cl.lobbyCode=code; cl.playerName=msg.name||"Glader"; cl.appearance=msg.appearance||{};
      cl.x=0; cl.y=0; cl.hp=100; cl.equipped="sword"; cl.inMaze=false;
      wsSend(cl.socket,{type:"LOBBY_CREATED",code,info:lobbyInfo(code)});
      console.log(`[+] Lobby ${code} by ${cl.playerName}`);
      break;
    }
    case "JOIN_LOBBY": {
      const code=msg.code, l=lobbies[code];
      if (!l)        { wsSend(cl.socket,{type:"ERROR",msg:"Lobby not found"}); return; }
      if (l.started) { wsSend(cl.socket,{type:"ERROR",msg:"Game already started"}); return; }
      if (l.players.length>=8){ wsSend(cl.socket,{type:"ERROR",msg:"Lobby full"}); return; }
      l.players.push(id);
      cl.lobbyCode=code; cl.playerName=msg.name||("Glader#"+l.players.length);
      cl.appearance=msg.appearance||{}; cl.x=0; cl.y=0; cl.hp=100; cl.equipped="sword"; cl.inMaze=false;
      wsSend(cl.socket,{type:"JOINED_LOBBY",info:lobbyInfo(code)});
      broadcast(code,{type:"PLAYER_JOINED",info:lobbyInfo(code)},id);
      console.log(`[+] ${cl.playerName} joined ${code}`);
      break;
    }
    case "START_GAME": {
      const l=lobbies[cl.lobbyCode]; if(!l||l.host!==id) return;
      l.started=true;
      const gx=44,gy=44,gw=12;
      l.players.forEach((pid,i)=>{
        const pc=clients[pid]; if(!pc) return;
        pc.x=(gx+gw/2)*32+i*32; pc.y=(gy+gw/2)*32;
      });
      broadcast(cl.lobbyCode,{type:"GAME_STARTED",info:lobbyInfo(cl.lobbyCode)});
      console.log(`[>] Game started in ${cl.lobbyCode} (${l.players.length} players)`);
      break;
    }
    case "PLAYER_UPDATE": {
      cl.x=msg.x||cl.x; cl.y=msg.y||cl.y; cl.hp=msg.hp!==undefined?msg.hp:cl.hp;
      cl.equipped=msg.equipped||cl.equipped; cl.inMaze=msg.inMaze||false; cl.anim=msg.anim||{};
      if(cl.lobbyCode) broadcast(cl.lobbyCode,{
        type:"PLAYER_MOVED",id:cl.id,x:cl.x,y:cl.y,hp:cl.hp,
        equipped:cl.equipped,inMaze:cl.inMaze,anim:cl.anim,
        name:cl.playerName,appearance:cl.appearance},id);
      break;
    }
    case "GAME_EVENT":
      if(cl.lobbyCode) broadcast(cl.lobbyCode,{type:"GAME_EVENT",event:msg.event,data:msg.data,from:cl.id,name:cl.playerName},id);
      break;
    case "CHAT":
      if(cl.lobbyCode) broadcast(cl.lobbyCode,{type:"CHAT",from:cl.playerName,text:(msg.text||"").substring(0,100)});
      break;
    case "PING": wsSend(cl.socket,{type:"PONG"}); break;
  }
}

// ── Day/night tick ────────────────────────────────────────────────────────────
setInterval(()=>{
  for(const[code,l] of Object.entries(lobbies)){
    if(!l.started) continue;
    l.time=(l.time||0)+1;
    const t=l.time%(180+180), wasDay=l.isDay;
    l.isDay=t<180;
    if(wasDay!==l.isDay){
      if(l.isDay) l.day++;
      broadcast(code,{type:"TIME_UPDATE",day:l.day,isDay:l.isDay,time:l.time});
    }
  }
},1000);

// ── HTTP + WS server ──────────────────────────────────────────────────────────
const server = http.createServer((req,res)=>{
  if(req.url==="/"||req.url==="/game"||req.url.startsWith("/?")) {
    res.writeHead(200,{"Content-Type":"text/html; charset=utf-8"});
    res.end(GAME_HTML); return;
  }
  if(req.url==="/health"){
    res.writeHead(200,{"Content-Type":"application/json"});
    res.end(JSON.stringify({ok:true,lobbies:Object.keys(lobbies).length,players:Object.keys(clients).length}));
    return;
  }
  if(req.url==="/manifest.json"){
    res.writeHead(200,{"Content-Type":"application/manifest+json"});
    res.end(JSON.stringify({
      name:"The Maze Runner",
      short_name:"MazeRunner",
      description:"Multiplayer survival maze game",
      start_url:"/",
      display:"fullscreen",
      orientation:"landscape",
      background_color:"#000000",
      theme_color:"#000000",
      icons:[
        {src:"/icon-192.png",sizes:"192x192",type:"image/png",purpose:"any maskable"},
        {src:"/icon-512.png",sizes:"512x512",type:"image/png",purpose:"any maskable"}
      ]
    }));
    return;
  }
  if(req.url==="/sw.js"){
    res.writeHead(200,{"Content-Type":"application/javascript"});
    res.end(`
self.addEventListener('install',e=>{ self.skipWaiting(); });
self.addEventListener('activate',e=>{ e.waitUntil(clients.claim()); });
self.addEventListener('fetch',e=>{ e.respondWith(fetch(e.request).catch(()=>new Response('Offline'))); });
`);
    return;
  }
  // Generate a simple icon (coloured square with MR text as SVG->PNG would need canvas, use SVG instead)
  if(req.url==="/icon-192.png"||req.url==="/icon-512.png"){
    const size=req.url.includes('512')?512:192;
    const svg=`<svg xmlns='http://www.w3.org/2000/svg' width='${size}' height='${size}'><rect width='${size}' height='${size}' fill='#000'/><rect x='${size*0.05}' y='${size*0.05}' width='${size*0.9}' height='${size*0.9}' rx='${size*0.12}' fill='#0a0a0a' stroke='#e8c96b' stroke-width='${size*0.02}'/><text x='50%' y='44%' text-anchor='middle' fill='#e8c96b' font-family='monospace' font-size='${size*0.28}' font-weight='bold'>MR</text><text x='50%' y='70%' text-anchor='middle' fill='#666' font-family='monospace' font-size='${size*0.1}'>MAZE RUNNER</text></svg>`;
    res.writeHead(200,{"Content-Type":"image/svg+xml"});
    res.end(svg);
    return;
  }
  res.writeHead(404); res.end();
});

server.on("upgrade",(req,socket)=>{
  if(req.headers.upgrade?.toLowerCase()!=="websocket"){socket.destroy();return;}
  wsHandshake(req,socket);
  const id=nextId++;
  clients[id]={id,socket,lobbyCode:null,playerName:"",x:0,y:0,hp:100,appearance:{},equipped:"sword",inMaze:false};
  wsSend(socket,{type:"CONNECTED",id});
  let buf=Buffer.alloc(0);
  socket.on("data",chunk=>{
    buf=Buffer.concat([buf,chunk]);
    const frames=wsParseFrames(buf); buf=Buffer.alloc(0);
    for(const fr of frames){ if(fr.type==="close"){socket.destroy();return;} if(fr.type==="msg") handle(id,fr.data); }
  });
  socket.on("close",()=>{
    const cl=clients[id];
    if(cl?.lobbyCode){
      const l=lobbies[cl.lobbyCode];
      if(l){ l.players=l.players.filter(p=>p!==id); broadcast(cl.lobbyCode,{type:"PLAYER_LEFT",id,name:cl.playerName,info:lobbyInfo(cl.lobbyCode)});
        if(l.players.length===0){delete lobbies[cl.lobbyCode];console.log(`[-] Lobby ${cl.lobbyCode} closed`);} }
    }
    delete clients[id];
  });
  socket.on("error",()=>socket.destroy());
});

server.listen(PORT,"0.0.0.0",()=>{
  console.log(`\n🎮 MAZE RUNNER — http://localhost:${PORT}\n`);
});
